1	import AsyncStorage from '@react-native-async-storage/async-storage';
2	import {
3	  createContext,
4	  useCallback,
5	  useContext,
6	  useEffect,
7	  useMemo,
8	  useRef,
9	  useState,
10	  type ReactNode,
11	} from 'react';
12	
13	// Campaign-creation wizard state (US-049 through US-053). React-context + AsyncStorage
14	// persistence — not MMKV, because `react-native-mmkv` v4 is a Nitro module that
15	// cannot load in Expo Go (see Codebase Pattern #105, progress.txt). AsyncStorage
16	// satisfies the AC's "wizard store + MMKV" intent with a transport that actually
17	// boots in Expo Go. The wizard draft is not secret material, so AsyncStorage (vs
18	// expo-secure-store) is the correct fit.
19	//
20	// Shape covers all five steps up front so later stories (US-050 pre-conditions,
21	// US-051 post-conditions, US-052 samples + max, US-053 publish) can read and
22	// write their slices without a store rewrite. Step 1 (this story) only wires the
23	// first four fields; the rest are kept with empty-array / null defaults.
24	
25	export type WizardCurrency = 'USD' | 'EUR' | 'GBP';
26	
27	export type WizardPreConditionPlatform = 'tiktok' | 'instagram';
28	export type WizardPreConditionMetric = 'followers' | 'avg_views';
29	
30	export type WizardPreCondition = {
31	  id: string;
32	  platform: WizardPreConditionPlatform;
33	  metric: WizardPreConditionMetric;
34	  threshold: number;
35	};
36	
37	export type WizardPostCondition = {
38	  id: string;
39	  text: string;
40	};
41	
42	export type WizardDraft = {
43	  title: string;
44	  description: string;
45	  priceCents: number | null;
46	  currency: WizardCurrency;
47	  preConditions: WizardPreCondition[];
48	  postConditions: WizardPostCondition[];
49	  sampleUrls: string[];
50	  maxSubmissions: number | null;
51	};
52	
53	const EMPTY_DRAFT: WizardDraft = {
54	  title: '',
55	  description: '',
56	  priceCents: null,
57	  currency: 'USD',
58	  preConditions: [],
59	  postConditions: [],
60	  sampleUrls: [],
61	  maxSubmissions: null,
62	};
63	
64	const STORAGE_KEY = '@marketify/campaign-wizard-draft/v1';
65	const PERSIST_DEBOUNCE_MS = 250;
66	
67	type WizardContextValue = {
68	  draft: WizardDraft;
69	  hydrated: boolean;
70	  setField: <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => void;
71	  setPartial: (patch: Partial<WizardDraft>) => void;
72	  resetDraft: () => Promise<void>;
73	};
74	
75	const WizardContext = createContext<WizardContextValue | null>(null);
76	
77	function isWizardDraftShape(value: unknown): value is WizardDraft {
78	  if (!value || typeof value !== 'object') return false;
79	  const v = value as Record<string, unknown>;
80	  return (
81	    typeof v.title === 'string' &&
82	    typeof v.description === 'string' &&
83	    (v.priceCents === null || typeof v.priceCents === 'number') &&
84	    (v.currency === 'USD' || v.currency === 'EUR' || v.currency === 'GBP') &&
85	    Array.isArray(v.preConditions) &&
86	    Array.isArray(v.postConditions) &&
87	    Array.isArray(v.sampleUrls) &&
88	    (v.maxSubmissions === null || typeof v.maxSubmissions === 'number')
89	  );
90	}
91	
92	export function WizardProvider({ children }: { children: ReactNode }) {
93	  const [draft, setDraft] = useState<WizardDraft>(EMPTY_DRAFT);
94	  const [hydrated, setHydrated] = useState(false);
95	  const persistTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
96	
97	  useEffect(() => {
98	    let cancelled = false;
99	    void (async () => {
100	      try {
101	        const raw = await AsyncStorage.getItem(STORAGE_KEY);
102	        if (cancelled) return;
103	        if (raw) {
104	          const parsed: unknown = JSON.parse(raw);
105	          if (isWizardDraftShape(parsed)) {
106	            setDraft(parsed);
107	          }
108	        }
109	      } catch {
110	        // Corrupted / missing draft — start clean. No user-visible error:
111	        // the wizard is a local-first flow and an empty draft is the right
112	        // fallback.
113	      } finally {
114	        if (!cancelled) setHydrated(true);
115	      }
116	    })();
117	    return () => {
118	      cancelled = true;
119	    };
120	  }, []);
121	
122	  const schedulePersist = useCallback((next: WizardDraft) => {
123	    if (persistTimer.current) clearTimeout(persistTimer.current);
124	    persistTimer.current = setTimeout(() => {
125	      void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(next));
126	    }, PERSIST_DEBOUNCE_MS);
127	  }, []);
128	
129	  useEffect(() => {
130	    return () => {
131	      if (persistTimer.current) clearTimeout(persistTimer.current);
132	    };
133	  }, []);
134	
135	  const setField = useCallback(
136	    <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => {
137	      setDraft((prev) => {
138	        const next = { ...prev, [key]: value };
139	        schedulePersist(next);
140	        return next;
141	      });
142	    },
143	    [schedulePersist],
144	  );
145	
146	  const setPartial = useCallback(
147	    (patch: Partial<WizardDraft>) => {
148	      setDraft((prev) => {
149	        const next = { ...prev, ...patch };
150	        schedulePersist(next);
151	        return next;
152	      });
153	    },
154	    [schedulePersist],
155	  );
156	
157	  const resetDraft = useCallback(async () => {
158	    if (persistTimer.current) {
159	      clearTimeout(persistTimer.current);
160	      persistTimer.current = null;
161	    }
162	    setDraft(EMPTY_DRAFT);
163	    await AsyncStorage.removeItem(STORAGE_KEY);
164	  }, []);
165	
166	  const value = useMemo<WizardContextValue>(
167	    () => ({ draft, hydrated, setField, setPartial, resetDraft }),
168	    [draft, hydrated, setField, setPartial, resetDraft],
169	  );
170	
171	  return <WizardContext.Provider value={value}>{children}</WizardContext.Provider>;
172	}
173	
174	export function useWizard(): WizardContextValue {
175	  const ctx = useContext(WizardContext);
176	  if (!ctx) {
177	    throw new Error('useWizard must be used inside <WizardProvider>');
178	  }
179	  return ctx;
180	}
