9	// crashes under Expo Go + SDK 54 new-arch ("expected dynamic type 'boolean'"),
10	// so we drive tab switching with `router.navigate` + `usePathname` instead.
11	// Revisit and replace with `<Tabs>` when a dev-client build lands.
12	export type TabDef = {
13	  label: string;
14	  icon: LucideIcon;
15	  path: Href;
16	  // Pathname that `usePathname()` reports for this tab — URL-stripped of the
17	  // route group (`/(creator)/discover` → `/discover`). We cannot derive this
18	  // from `path` because group parens are invisible in the URL.
19	  activePathname: string;
20	  testID?: string;
21	};
22	
23	export type TabBarProps = {
24	  tabs: TabDef[];
25	};
26	
27	export function TabBar({ tabs }: TabBarProps) {
28	  const router = useRouter();
29	  const pathname = usePathname();
30	
31	  return (
32	    <SafeAreaView style={styles.safeArea}>
33	      <View style={styles.bar}>
34	        {tabs.map((tab) => {
35	          const focused = isActive(pathname, tab.activePathname);
36	          const color = focused ? colors.primary : colors.ink70;
37	          const Icon = tab.icon;
38	          return (
39	            <Pressable
40	              key={tab.activePathname}
41	              style={styles.tab}
42	              onPress={() => router.navigate(tab.path)}
43	              accessibilityRole="tab"
44	              accessibilityState={{ selected: focused }}
45	              accessibilityLabel={tab.label}
46	              testID={tab.testID}
47	            >
48	              <Icon size={24} color={color} strokeWidth={focused ? 2.5 : 1.5} />
49	              <Text style={[styles.label, { color }]} allowFontScaling={false}>
50	                {tab.label}
51	              </Text>
52	            </Pressable>
53	          );
54	        })}
55	      </View>
56	    </SafeAreaView>
57	  );
58	}
59	
60	// Active when the current path exactly matches OR is a nested route of the tab.
61	// e.g. `/campaigns/new/step-1` still lights the Campaigns tab.
62	function isActive(pathname: string, tabActivePath: string): boolean {
63	  if (pathname === tabActivePath) return true;
64	  if (tabActivePath === '/') return false;
65	  return pathname.startsWith(`${tabActivePath}/`);
66	}
67	
